queries.sql:
SELECT table_name, db_name, org_id, table_type, engine, table_rows 
FROM table_list 
WHERE org_id = 10006;

SELECT cl.column_name, cl.table_name, cl.db_name 
FROM column_list AS cl 
WHERE cl.data_type = 'varchar' AND cl.org_id = 10006;

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.is_nullable = 0 AND cl.org_id = 10006;

SELECT im.index_id, im.index_name, im.column_name 
FROM indexes_metadata im 
WHERE im.org_id = 10006 AND im.non_unique = 0;

SELECT tl.table_name, tl.engine 
FROM table_list AS tl 
WHERE tl.org_id = 10006;

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.extra_info LIKE '%auto_increment%' AND cl.org_id = 10006;

SELECT tl.table_name, tl.table_rows 
FROM table_list AS tl 
WHERE tl.org_id = 10006;

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type, cl.is_nullable, cl.column_key, cl.extra_info
FROM column_list AS cl
WHERE cl.org_id = 10006 AND cl.extra_info LIKE '%DEFAULT%';

SELECT r.source_table, r.source_column, r.target_table, r.target_column 
FROM relationships AS r 
WHERE r.org_id = 10006;

SELECT im.index_id, im.db_name, im.table_name, im.index_name, im.column_name 
FROM indexes_metadata im 
WHERE im.org_id = 10006 AND im.non_unique = 1;

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND (cl.data_type = 'date' OR cl.data_type = 'datetime');

SELECT column_name, table_name, db_name, data_type 
FROM column_list 
WHERE org_id = 10006 AND data_type = 'BIGINT';

SELECT cl.column_name, cl.table_name, cl.data_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND cl.data_type = 'boolean';

SELECT cl.column_name, cl.table_name, cl.data_type, cl.column_type
FROM column_list AS cl
WHERE cl.org_id = 10006 AND (cl.data_type = 'TEXT' OR cl.data_type = 'LONGTEXT');

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.is_nullable = 1 AND cl.org_id = 10006;

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.is_nullable
FROM column_list AS cl
WHERE cl.org_id = 10006 AND (cl.column_name = 'id' OR cl.column_name LIKE '%id%');

SELECT tl.table_name, tl.table_rows 
FROM table_list AS tl 
WHERE tl.org_id = 10006;

SELECT table_name, db_name, org_id, created_at, updated_at 
FROM table_list 
WHERE org_id = 10006 AND created_at IS NOT NULL AND updated_at IS NOT NULL;

SELECT cl.column_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND cl.data_type = 'enum';

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND cl.data_type = 'INT';

SELECT cl.column_name, cl.table_name, cl.data_type
FROM column_list AS cl
WHERE cl.org_id = 10006 AND (cl.data_type = 'decimal' OR cl.data_type = 'float');

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND cl.column_name LIKE '%hash%';

SELECT tl.table_name, tl.db_name, tl.org_id, tl.is_deleted, tl.created_at, tl.updated_at, tl.table_type, tl.engine, tl.table_rows
FROM table_list AS tl
WHERE tl.org_id = 10006 AND (tl.is_deleted IS NOT NULL);

SELECT cl.column_name, cl.table_name, cl.data_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006 AND cl.column_name LIKE '%expires%';

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type, cl.is_nullable, cl.column_key, cl.extra_info, cl.ordinal_position, cl.created_at, cl.updated_at
FROM column_list AS cl
WHERE cl.org_id = 10006 AND cl.data_type = 'TIMESTAMP';

SELECT tl.table_name, tl.db_name, tl.table_type, tl.engine, tl.table_rows 
FROM table_list AS tl 
WHERE tl.org_id = 10006 AND tl.table_type = 'lookup';

SELECT cl.column_name, cl.table_name, cl.db_name, cl.data_type, cl.column_type 
FROM column_list AS cl
WHERE cl.org_id = 10006 AND cl.column_key = 'UNI';

SELECT COUNT(*) AS total_columns 
FROM column_list 
WHERE org_id = 10006;

SELECT tl.table_name, tl.table_type, tl.engine, tl.table_rows 
FROM table_list AS tl 
WHERE tl.org_id = 10006;

SELECT COUNT(*) AS total_tables 
FROM table_list 
WHERE org_id = 10006;

SELECT DISTINCT cl.data_type 
FROM column_list AS cl 
WHERE cl.org_id = 10006;

SELECT COUNT(*) AS total_columns 
FROM column_list 
WHERE org_id = 10006;

SELECT COUNT(cl.column_name) AS varchar_column_count
FROM column_list AS cl
WHERE cl.data_type = 'varchar' AND cl.org_id = 10006;

SELECT COUNT(cl.column_name) AS int_column_count
FROM column_list AS cl
WHERE cl.data_type = 'INT' AND cl.org_id = 10006;

SELECT COUNT(cl.column_name) AS bigint_column_count
FROM column_list AS cl
WHERE cl.data_type = 'BIGINT' AND cl.org_id = 10006;

SELECT COUNT(cl.column_name) AS text_column_count
FROM column_list AS cl
WHERE cl.data_type = 'TEXT' AND cl.org_id = 10006;

SELECT COUNT(cl.column_name) AS column_count
FROM column_list AS cl
WHERE cl.data_type IN ('DATETIME', 'TIMESTAMP') AND cl.org_id = 10006;

SELECT DISTINCT db_type 
FROM db 
WHERE org_id = 10006;

SELECT COUNT(cl.column_name) AS enum_column_count
FROM column_list AS cl
WHERE cl.data_type = 'enum' AND cl.org_id = 10006;

SELECT COUNT(*) AS total_foreign_key_relationships 
FROM relationships 
WHERE org_id = 10006;

SELECT COUNT(*) AS total_indexes 
FROM indexes_metadata 
WHERE org_id = 10006;
